<template><div class="page"><a-card :bordered="false"><a-tabs v-model:activeKey="type" @change="reload"><a-tab-pane key="order" tab="采购订单"/><a-tab-pane key="receipt" tab="到货单"/><a-tab-pane key="inbound" tab="入库单"/><a-tab-pane key="inventory" tab="库存余额"/></a-tabs><a-space class="search"><a-input v-model:value="query.code" placeholder="单据编号/物料编码" allow-clear @pressEnter="reload"/><a-select v-if="type==='inventory'" v-model:value="query.warehouseCode" placeholder="仓库" allow-clear style="width:160px"><a-select-option value="MAIN">主仓</a-select-option></a-select><a-button type="primary" @click="reload">查询</a-button><a-button @click="reset">重置</a-button><a-button type="primary" ghost @click="openAdd">新增</a-button><a-button danger :disabled="!selected.length" @click="remove">删除</a-button></a-space><a-table :loading="loading" :data-source="rows" :columns="columns" row-key="id" :pagination="pagination" @change="pageChange" :row-selection="{selectedRowKeys:selected,onChange:keys=>selected=keys}"><template #bodyCell="{column,record}"><template v-if="column.key==='action'"><a-space><a @click="openEdit(record)">编辑</a><a @click="openDetail(record)">详情</a></a-space></template></template></a-table></a-card><a-modal v-model:open="open" :title="editing?'编辑':'新增'" @ok="save"><a-form :model="form" layout="vertical"><a-form-item v-for="f in fields" :key="f.key" :label="f.label"><a-input v-model:value="form[f.key]"/></a-form-item></a-form></a-modal><a-drawer v-model:open="detailOpen" title="详情" width="720"><a-descriptions bordered :column="1"><a-descriptions-item v-for="f in fields" :key="f.key" :label="f.label">{{ detail[f.key] || '-' }}</a-descriptions-item></a-descriptions><a-table v-if="detail.lines" :data-source="detail.lines" :columns="lineColumns" row-key="id"/></a-drawer></div></template>
<script setup>import {ref,reactive,computed,onMounted} from 'vue';import {message} from 'ant-design-vue';import {purchaseOrderApi,purchaseReceiptApi,purchaseInboundApi,inventoryBalanceApi} from '@/api/mes/purchase';const type=ref('order'),rows=ref([]),loading=ref(false),selected=ref([]),open=ref(false),detailOpen=ref(false),editing=ref(false),detail=ref({}),form=reactive({}),query=reactive({pageNum:1,pageSize:10,code:'',warehouseCode:''});const apis={order:purchaseOrderApi,receipt:purchaseReceiptApi,inbound:purchaseInboundApi,inventory:inventoryBalanceApi};const defs={order:{title:'采购订单',code:'orderCode',fields:[['orderCode','订单编号'],['supplierName','供应商'],['orderDate','订单日期'],['expectedDate','预计到货'],['status','状态'],['totalQuantity','总数量'],['totalAmount','总金额']]},receipt:{title:'到货单',code:'receiptCode',fields:[['receiptCode','到货单号'],['orderCode','采购订单'],['receiptDate','到货日期'],['status','状态'],['inspectionStatus','检验状态'],['totalQuantity','到货数量']]},inbound:{title:'入库单',code:'inboundCode',fields:[['inboundCode','入库单号'],['receiptCode','到货单'],['inboundDate','入库日期'],['warehouseCode','仓库'],['status','状态'],['totalQuantity','入库数量']]},inventory:{title:'库存余额',code:'materialCode',fields:[['materialCode','物料编码'],['materialName','物料名称'],['warehouseCode','仓库'],['locationCode','库位'],['lotNo','批次'],['unit','单位'],['quantity','库存数量'],['availableQuantity','可用数量'],['lockedQuantity','锁定数量'],['status','状态']]}};const fields=computed(()=>defs[type.value].fields.map(x=>({key:x[0],label:x[1]}))),columns=computed(()=>fields.value.map(f=>({title:f.label,dataIndex:f.key,key:f.key})).concat([{title:'操作',key:'action'}])),lineColumns=[{title:'物料编码',dataIndex:'materialCode'},{title:'物料名称',dataIndex:'materialName'},{title:'数量',dataIndex:'orderQuantity'},{title:'单位',dataIndex:'unit'}];const pagination=reactive({current:1,pageSize:10,total:0,showSizeChanger:true});async function reload(){loading.value=true;query.code=query.code||'';const q={pageNum:pagination.current,pageSize:pagination.pageSize};q[defs[type.value].code]=query.code;if(query.warehouseCode)q.warehouseCode=query.warehouseCode;const r=await apis[type.value].list(q);rows.value=r.rows||[];pagination.total=r.total||0;loading.value=false}function reset(){query.code='';query.warehouseCode='';pagination.current=1;reload()}function pageChange(p){pagination.current=p.current;pagination.pageSize=p.pageSize;reload()}function openAdd(){editing.value=false;Object.keys(form).forEach(k=>delete form[k]);fields.value.forEach(f=>form[f.key]='');open.value=true}function openEdit(r){editing.value=true;Object.assign(form,r);open.value=true}async function save(){await (editing.value?apis[type.value].update(form):apis[type.value].add(form));message.success('保存成功');open.value=false;reload()}async function openDetail(r){detail.value=(await apis[type.value].get(r.id)).data||r;detailOpen.value=true}async function remove(){await apis[type.value].remove(selected.value.join(','));message.success('删除成功');selected.value=[];reload()}onMounted(reload)</script>
